    //bepaalt de gegevens nodig voor het rekenen van de rsz in het vorig kwartaal bij aanwezigheid opzegvergoeding
    private static void gegevensVorigeKwartaal(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getRekenTijd();
        PersoonsDataManager dataManager = opdrachtContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        boolean theoretisch = opdrachtContext.getBoolean(RekenChainKey.THEORETISCHE_JAARWEDDE_MODUS_KEY);
        boolean gegevensVorigKwartaal = dataManager.isOpdrachtInOpzegOpEerstDagKwartaal(opdracht) && !theoretisch;
        LocalDate selectieVorigKwartaal = null;
        Opper opperVorigKwartaal = null;
        if (gegevensVorigKwartaal) {
            selectieVorigKwartaal = TimeTools.bepaalSelectieDatumVorigKwartaalDmfappl(rekenTijd);
            Persoon persoonVorigKwartaal = dataManager.getPersoonOpDatum(selectieVorigKwartaal);
            Opdracht opdrachtVorigKwartaal = RekenTools.findOpdracht(persoonVorigKwartaal, opdracht.getId());
            opperVorigKwartaal = RekenTools.getOpperLaatsteGegevens(opdrachtVorigKwartaal);
        }
        opdrachtContext.put(RekenChainKey.RSZ_VORIG_KWARTAAL_KEY, gegevensVorigKwartaal);
        opdrachtContext.put(RekenChainKey.SELECTIE_DATUM_VORIG_KWARTAAL_KEY, selectieVorigKwartaal);
        opdrachtContext.put(RekenChainKey.OPPER_VORIG_KWARTAAL_KEY, opperVorigKwartaal);
    }

    private static Pensioenstelsel bepaalPensioenstelsel(SleutelGegevens aggregaat) {
        try {
            return aggregaat.getPensioenStelsel();
        } catch (MessageException e) {
            log.trace("Komt voor als pensioenstelsel geen sleutel is (pre Dmfa 2022)", e);
            return Pensioenstelsel.NVT_GEEN_KATEGORIE;
        }
    }

    @Override
    public void berekenSocialeBijdragenRszppoPlichtig(RekenContext opdrachtContext, Opdracht opdracht) {
        if (opdracht.getHoedanigheid() != Hoedanigheid.VRIJWILLIGERS) {
            gegevensVorigeKwartaal(opdrachtContext, opdracht);
            verdeelBasisRsz(opdrachtContext, opdracht);
            sommeerBasissen(opdrachtContext, opdracht, BASIS_RSZ_KEYS);
            bepaalBijdragen(opdrachtContext, opdracht);
        }
    }

    @Override
    public void berekenSocialeBijdrageMonitoren(RekenContext opdrachtContext, Opdracht opdracht) {
        berekenSocialeBijdragenRszppoPlichtig(opdrachtContext, opdracht);
    }

    @Override
    public void verdeelBasisRsz(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getRekenTijd();
        LoonElementManager manager = opdrachtContext.getLoonElementManager();
        RegulManager regulManager = opdrachtContext.getRegulManager();
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        boolean gegevensVorigKwartaal = opdrachtContext.getBoolean(RekenChainKey.RSZ_VORIG_KWARTAAL_KEY);
        if (gegevensVorigKwartaal) {
            LocalDate gegevensDatum = opdrachtContext.getUnchecked(RekenChainKey.SELECTIE_DATUM_VORIG_KWARTAAL_KEY);
            Opper opperVorigKwartaal = opdrachtContext.getUnchecked(RekenChainKey.OPPER_VORIG_KWARTAAL_KEY);
            SleutelGegevens aggregaat = new SleutelGegevensSingleOpper(opperVorigKwartaal);
            Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
            boolean bestuurBerekentTweedePensioenPijler = bestuurBerekentTweedePensioenPijler(rekenTijd, gegevensDatum);
            verdeelBasisRsz(rekenTijd, hoedanigheid, aggregaat, bestuurBerekentTweedePensioenPijler, loonElementen, regulManager, gegevensDatum);
        } else {
            LocalDate gegevensDatum = rekenTijd.eindDatum;
            SleutelSamenNemer aggregatorBasis = new SleutelSamenNemer();
            List<SleutelGegevens> aggregaten = aggregatorBasis.neemSamenVoorSleutel(opdracht, getBasisRszSleutel());
            boolean bestuurBerekentTweedePensioenPijler = bestuurBerekentTweedePensioenPijler(rekenTijd, rekenTijd.eindDatum);
            for (SleutelGegevens aggregaat : aggregaten) {
                Collection<LoonElement> loonElementen = aggregaat.getOpperElementen(manager);
                verdeelBasisRsz(rekenTijd, hoedanigheid, aggregaat, bestuurBerekentTweedePensioenPijler, loonElementen, regulManager, gegevensDatum);
            }
        }
    }

    private void verdeelBasisRsz(
            RekenTijd rekenTijd, Hoedanigheid hoedanigheid, SleutelGegevens aggregaat,
            boolean bestuurBerekentTweedePensioenPijler, Collection<LoonElement> loonElementen, RegulManager regulManager, LocalDate gegevensDatum) {
        Gsd typeGsd = getTypeGsd(rekenTijd, gegevensDatum);
        DmfapplStatuutDmfappl statuutDmfappl = aggregaat.getStatuutDmfappl();

        WerkgeversCategorie werkgeversCategorie = aggregaat.getWerkgeversCategorie();
        DmfapplWnkengetal werknemersKengetal = aggregaat.getWerknemersKengetal();
        CategorieKengetal categorieKengetal = CategorieKengetalFactory.getCategorieKengetal(rekenTijd, werkgeversCategorie, werknemersKengetal);


        BasisRszVerdelerOptions basisRszVerdelerOptions =
                createBasisRszVerdelerOptions(rekenTijd, aggregaat, bestuurBerekentTweedePensioenPijler, gegevensDatum, categorieKengetal);

        Pensioenstelsel pensioenStelsel = bepaalPensioenstelsel(aggregaat);
        CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel =
                CategorieKengetalStatuutPensioenstelselFactory.create(rekenTijd, werkgeversCategorie, werknemersKengetal, statuutDmfappl, pensioenStelsel);
        BasisRszVerdeler basisRszVerdeler =
                getBasisRszVerdelerZonderLoonElement(hoedanigheid, regulManager, gegevensDatum,
                        typeGsd, categorieKengetalStatuutPensioenstelsel, basisRszVerdelerOptions);
        for (LoonElement loonElement : loonElementen) {
            basisRszVerdeler.setLoonElement(loonElement);
            basisRszVerdeler.verdeelBasisRsz();
        }
    }

    protected Set<Sleutel<?>> getBasisRszSleutel() {
        return BASIS_RSZ_SLEUTEL;
    }

    protected BasisRszVerdelerOptions createBasisRszVerdelerOptions(
            RekenTijd rekenTijd, SleutelGegevens aggregaat, boolean bestuurBerekentTweedePensioenPijler, LocalDate gegevensDatum, CategorieKengetal categorieKengetal) {
        PensioenPijler2 pensioenPijler2 = PensioenPijler2Factory.create(rekenTijd, aggregaat);

        Constant constantTypeBijdrage = constantManager.getActualConstant(Konstanten.KST_TYPE_BIJDRAGE_PENS2, rekenTijd, gegevensDatum);
        int typeBijdrage = constantTypeBijdrage.getInteger();
        boolean berekenTweedePensioenPijler = pensioenPijler2.komtInAanmerking() && bestuurBerekentTweedePensioenPijler && typeBijdrage != PROLOCUS_0_PRCT;

        PensioenPijler2BonusBijdrage pensioenPijler2BonusBijdrage =
                PensioenPijler2BonusBijdrageFactory.create(aggregaat, constantManager, rekenTijd, gegevensDatum);
        boolean bonusTweedePensioenPijler = pensioenPijler2BonusBijdrage.heeftBonusBijdrageTweedePensioenPijler();
        DmfapplCodeVermin verminderingsCode = aggregaat.getVerminderingsCode();
        boolean heeftVerminderingPatronaleRsz = heeftVerminderingPatronaleRsz(categorieKengetal, verminderingsCode, gegevensDatum);
        Constant prolocusConstante = constantManager.getActualConstant(Konstanten.KST_PROLOCUS, rekenTijd);
        boolean isProlocus = prolocusConstante.getJaneen();

        return BasisRszVerdelerOptions.builder()
                .berekenTweedePensioenPijler(berekenTweedePensioenPijler)
                .bonusTweedePensioenPijler(bonusTweedePensioenPijler)
                .heeftVerminderingPatronaleRsz(heeftVerminderingPatronaleRsz)
                .isProlocus(isProlocus)
                .build();
    }

    protected BasisRszVerdeler getBasisRszVerdelerZonderLoonElement(
            Hoedanigheid hoedanigheid, RegulManager regulManager, LocalDate gegevensDatum,
            Gsd typeGsd, CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel, BasisRszVerdelerOptions options) {
        return BasisRszVerdelerDmfappl.builder()
                .dmfapplBasisBijdrageService(dmfapplBasisBijdrageService)
                .apkPrincipeService(apkPrincipeService)
                .regulManager(regulManager)
                .hoedanigheid(hoedanigheid)
                .typeGsd(typeGsd)
                .categorieKengetalStatuutPensioenstelsel(categorieKengetalStatuutPensioenstelsel)
                .gegevensDatum(gegevensDatum)
                .options(options)
                .build();
    }

    private Gsd getTypeGsd(RekenTijd rekenTijd, LocalDate gegevensDatum) {
        Gsd typeGsd = Gsd.getByCode(constantManager.getActualConstant(Konstanten.KST_GSD_DMFAPPL, rekenTijd, gegevensDatum).getInteger());
        boolean cstRekenGsd = constantManager.getActualConstant(Konstanten.KST_REKEN_GSD, rekenTijd, gegevensDatum).getBoolean();
        if (!cstRekenGsd) {
            typeGsd = Gsd.NVT;
        }
        return typeGsd;
    }

    public boolean heeftVerminderingPatronaleRsz(CategorieKengetal categorieKengetal, DmfapplCodeVermin verminderingsCode, LocalDate zoekDatum) {
        return getVerminderingPatronaleBijdrageRsz(categorieKengetal, verminderingsCode, zoekDatum).signum() != 0;
    }

    private BigDecimal getVerminderingPatronaleBijdrageRsz(CategorieKengetal categorieKengetal, DmfapplCodeVermin verminderingsCode, LocalDate zoekDatum) {
        BigDecimal bijdragePercentage = BigDecimal.ZERO;
        DmfaVerminderingsPercentage verminderingsPercentage = dmfaVerminderingsPercentageService.getByWerkgeversCategorieWerknemersKengetalVerminderingsCodeDatum(
                categorieKengetal.getWerkgeversCategorie(), categorieKengetal.getDmfapplWnkengetal(), verminderingsCode, zoekDatum);
        if (verminderingsPercentage != null) {
            bijdragePercentage = verminderingsPercentage.getVerminderingsPercentage();
        }
        return bijdragePercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    public boolean bestuurBerekentTweedePensioenPijler(RekenTijd rekenTijd, LocalDate gegevensDatum) {
        PensioenPijler2Activator pensioenPijler2Activator = new PensioenPijler2Activator(rekenTijd, gegevensDatum, constantManager);
        return pensioenPijler2Activator.bestuurBerekentTweedePensioenPijler();
    }

    private void bepaalBijdragen(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);

        SleutelSamenNemer aggregatorBijdrage = new SleutelSamenNemer();
        List<SleutelGegevens> aggregaten = aggregatorBijdrage.neemSamenVoorSleutel(opdracht, getBijdrageRszSleutel());

        for (MoneyKey bijdrageKey : getBijdragen()) {
            berekenBijdrage(opdrachtContext, RszTools.bijdrageToBasis(bijdrageKey), bijdrageKey, aggregaten);
        }
        if (heeftPatronaleBijdrageMeerDan10Werknemers(opdracht.getWerkgever(), rekenTijd)) {
            berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_RSZ_KEY, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_MEER_DAN_10WERKNEMERS_KEY, aggregaten);
        }
        int typeBijdrage = constantManager.getActualConstant(Konstanten.KST_TYPE_BIJDRAGE_PENS2, rekenTijd).getInteger();

        if (typeBijdrage != PensioenPijler2TypeBijdrage.ANTWERPEN.getCode()) {
            berekenBijdrage2dePensioenPijler(opdrachtContext, opdracht, aggregaten);
        }
        berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_WVL_KEY, RekenRszKey.BIJDRAGE_WVL_KEY, aggregaten);
        berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_WVL_KEY, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_WVL_KEY, aggregaten);
        berekenPatronaleVerminderingOnthaalOuders(opdrachtContext, opdracht);
        berekenPatronaleVermindering707(opdrachtContext, opdracht);
    }

    private void berekenPatronaleVerminderingOnthaalOuders(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        PersoonsDataManager dataManager = opdrachtContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        LoonElementManager elementManager = opdrachtContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);

        BerekenPatronaleVerminderingOnthaalOuders patronaleVerminderingOnthaalOuders =
                new BerekenPatronaleVerminderingOnthaalOuders(dataManager, elementManager, rekenTijd);
        patronaleVerminderingOnthaalOuders.bereken(opdracht);
    }

    private void berekenPatronaleVermindering707(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        LoonElementManager elementManager = opdrachtContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
